"use client";

/**
 * <MarginMapScatter> — scatter of products (CM3% × true profit), bubble = revenue.
 *
 * Tier-2 per CHART-STANDARD §5.1. Bubbles are sorted big-to-small so small ones
 * sit on top.  No `preserveAspectRatio="none"` — viewBox = real px width.
 */

import { useChartSize } from "@/lib/useChartSize";
import { ChartStates, type ChartState } from "./_kit/ChartStates";

export type MarginScatterHealth =
  | "star"
  | "excellent"
  | "good"
  | "warning"
  | "critical";

export interface MarginScatterPoint {
  name: string;
  /** Contribution margin %, signed. X axis. */
  cm3: number;
  /** True profit in dollars. Y axis. */
  profit: number;
  /** Revenue — drives bubble radius. */
  rev: number;
  health: MarginScatterHealth;
}

export interface MarginMapScatterProps {
  data?: MarginScatterPoint[];
  selectedIndex?: number | null;
  onSelect?: (i: number | null) => void;
  state?: ChartState;
  label?: string;
  /** Color for each health bucket — defaults to the spec palette. */
  colorMap?: Record<MarginScatterHealth, string>;
}

const DEFAULT_COLOR: Record<MarginScatterHealth, string> = {
  star: "#1D9E75",
  excellent: "#1D9E75",
  good: "#8a8d94",
  warning: "#b88a2a",
  critical: "#d64545",
};

export const sampleMarginScatterData: MarginScatterPoint[] = [
  { name: "Monitor Arm", cm3: 41, profit: 15880, rev: 39600, health: "star" },
  { name: "Laptop Stand", cm3: 32, profit: 9090, rev: 28100, health: "excellent" },
  { name: "Standing Desk", cm3: 12, profit: 4950, rev: 38500, health: "warning" },
  { name: "Office Chair", cm3: 6, profit: 1680, rev: 25900, health: "warning" },
  { name: "Cylinder Stand", cm3: -7, profit: -980, rev: 13800, health: "critical" },
];

export function MarginMapScatter({
  data = sampleMarginScatterData,
  selectedIndex = null,
  onSelect,
  state = "ready",
  label = "Margin map",
  colorMap = DEFAULT_COLOR,
}: MarginMapScatterProps) {
  const { ref, width } = useChartSize({ min: 640, fallback: 920 });
  const MW = Math.max(640, width);
  const MH = 380;
  const padL = 60;
  const padR = 30;
  const padT = 24;
  const padB = 50;
  const plotW = MW - padL - padR;
  const plotH = MH - padT - padB;

  // Axis bounds. Derived from data so it doesn't lie when products change.
  const xMin = Math.min(-12, ...data.map((d) => d.cm3));
  const xMax = Math.max(50, ...data.map((d) => d.cm3));
  const yMaxD = Math.max(26000, ...data.map((d) => d.profit));
  const yMinD = Math.min(-6000, ...data.map((d) => d.profit));
  const maxRev = Math.max(...data.map((d) => d.rev), 1);

  const mx = (v: number) => padL + ((v - xMin) / (xMax - xMin || 1)) * plotW;
  const my = (v: number) =>
    padT + (1 - (v - yMinD) / (yMaxD - yMinD || 1)) * plotH;
  const rOf = (rev: number) => 8 + Math.sqrt(rev / maxRev) * 22;

  const sortedByRev = [...data]
    .map((p, idx) => ({ p, idx }))
    .sort((a, b) => b.p.rev - a.p.rev);

  return (
    <div ref={ref}>
      <ChartStates state={state} height={MH} label={label}>
        <svg
          className={`map-svg${selectedIndex != null ? " dimmed" : ""}`}
          viewBox={`0 0 ${MW} ${MH}`}
        >
          {/* Y gridlines */}
          {[0, 10000, 20000].map((v) => (
            <g key={v}>
              <line x1={padL} y1={my(v)} x2={MW - padR} y2={my(v)} stroke="rgba(0,0,0,0.05)" strokeWidth={1} />
              <text
                x={padL - 8}
                y={my(v) + 4}
                fontSize="11"
                fill="#8a8d94"
                textAnchor="end"
                fontFamily="var(--font-mono)"
              >
                {v === 0 ? "$0" : `$${(v / 1000).toFixed(0)}K`}
              </text>
            </g>
          ))}
          {/* Zero line for CM3 */}
          <line
            x1={mx(0)}
            y1={padT}
            x2={mx(0)}
            y2={MH - padB}
            stroke="var(--loss)"
            strokeWidth={1.4}
            strokeDasharray="5 4"
            opacity={0.5}
          />
          <text
            x={mx(0) + 4}
            y={padT + 12}
            fontSize="9.5"
            fontWeight="600"
            fill="var(--loss)"
            fontFamily="var(--font-mono)"
            letterSpacing="0.06em"
          >
            0% — BREAK-EVEN
          </text>
          {/* axis labels */}
          <text
            x={MW - padR}
            y={MH - 14}
            fontSize="9.5"
            fill="var(--ink-3)"
            textAnchor="end"
            fontFamily="var(--font-mono)"
            letterSpacing="0.08em"
          >
            CM3% (CONTRIBUTION MARGIN) →
          </text>
          <text
            x={padL}
            y={padT - 6}
            fontSize="9.5"
            fill="var(--ink-3)"
            fontFamily="var(--font-mono)"
            letterSpacing="0.08em"
          >
            ↑ TRUE PROFIT $
          </text>

          {/* Bubbles */}
          {sortedByRev.map(({ p, idx }) => {
            const cx = mx(p.cm3);
            const cy = my(p.profit);
            const r = rOf(p.rev);
            const fill = colorMap[p.health];
            return (
              <g key={p.name}>
                <circle
                  className={`bubble${selectedIndex === idx ? " sel" : ""}`}
                  cx={cx}
                  cy={cy}
                  r={r}
                  fill={fill}
                  fillOpacity={0.82}
                  stroke="#fff"
                  strokeWidth={1.5}
                  style={onSelect ? { cursor: "pointer" } : undefined}
                  onClick={() => onSelect?.(selectedIndex === idx ? null : idx)}
                />
              </g>
            );
          })}

          {/* Star + dust labels (derived from data — no hardcoded names) */}
          {(() => {
            if (data.length === 0) return null;
            const star = [...data].sort((a, b) => b.profit - a.profit)[0];
            const dust = [...data].sort((a, b) => a.cm3 - b.cm3)[0];
            return [
              { p: star, color: "var(--d-finance)" },
              { p: dust, color: "var(--loss)" },
            ].map(({ p, color }) => {
              const cx = mx(p.cm3);
              const cy = my(p.profit);
              const r = rOf(p.rev);
              return (
                <text
                  key={p.name + color}
                  x={cx}
                  y={cy - r - 8}
                  fontSize="11"
                  fontWeight="600"
                  fill={color}
                  textAnchor="middle"
                  fontFamily="var(--font-sans)"
                >
                  {p.name}
                </text>
              );
            });
          })()}
        </svg>
      </ChartStates>
    </div>
  );
}
