/**
 * Mock data for Finance · Margin Analysis.
 *
 * 9 products, each with revenue + 4 cost components (COGS, shipping, ads,
 * returns). True profit and CM3% are derived. Health bucket (star /
 * excellent / good / warning / critical) drives verdict + color in the
 * scatter map, panels, and table.
 */

export type MarginHealth = "star" | "excellent" | "good" | "warning" | "critical";
export type MarginBucket = "win" | "warn" | "loss";

export interface MarginProductRaw {
  name: string;
  sub: string;
  rev: number;
  cogs: number;
  ship: number;
  ads: number;
  ret: number;
  spark: number[];
}

export interface MarginProduct extends MarginProductRaw {
  gross: number;
  grossPct: number;
  profit: number;
  cm3: number;
  health: MarginHealth;
  bucket: MarginBucket;
}

const RAW: MarginProductRaw[] = [
  { name: "Monitor Arm", sub: "412 units · $96 avg", rev: 39600, cogs: 16600, ship: 2400, ads: 4200, ret: 520, spark: [34, 36, 38, 39, 41] },
  { name: "Laptop Stand", sub: "520 units · $54 avg", rev: 28100, cogs: 12100, ship: 2900, ads: 3600, ret: 410, spark: [31, 32, 33, 34, 34] },
  { name: "Ergonomic Keyboard", sub: "288 units · $119 avg", rev: 34300, cogs: 15800, ship: 2100, ads: 5200, ret: 980, spark: [30, 29, 28, 28, 29] },
  { name: "Standing Desk", sub: "94 units · $410 avg", rev: 38500, cogs: 21200, ship: 6400, ads: 4100, ret: 1850, spark: [22, 21, 20, 18, 17] },
  { name: "Desk Mat", sub: "910 units · $29 avg", rev: 26400, cogs: 9200, ship: 3100, ads: 2400, ret: 280, spark: [36, 37, 38, 38, 39] },
  { name: "Cable Organizer", sub: "640 units · $22 avg", rev: 14100, cogs: 5600, ship: 2300, ads: 1900, ret: 160, spark: [33, 34, 34, 35, 35] },
  { name: "Office Chair", sub: "108 units · $240 avg", rev: 25900, cogs: 13900, ship: 5100, ads: 3800, ret: 1420, spark: [19, 18, 16, 14, 12] },
  { name: "Webcam Cover", sub: "1240 units · $9 avg", rev: 11200, cogs: 3100, ship: 1800, ads: 1200, ret: 90, spark: [40, 41, 41, 42, 42] },
  { name: "Cylinder Stand", sub: "186 units · $74 avg", rev: 13800, cogs: 7300, ship: 2600, ads: 4500, ret: 380, spark: [18, 12, 6, 1, -3] },
];

export const PRODUCTS: MarginProduct[] = RAW.map((p) => {
  const gross = p.rev - p.cogs;
  const grossPct = (gross / p.rev) * 100;
  const profit = p.rev - p.cogs - p.ship - p.ads - p.ret;
  const cm3 = (profit / p.rev) * 100;
  let health: MarginHealth;
  let bucket: MarginBucket;
  if (cm3 < 0) {
    health = "critical";
    bucket = "loss";
  } else if (cm3 < 10) {
    health = "warning";
    bucket = "warn";
  } else if (cm3 >= 38) {
    health = "star";
    bucket = "win";
  } else if (cm3 >= 28) {
    health = "excellent";
    bucket = "win";
  } else {
    health = "good";
    bucket = "win";
  }
  return { ...p, gross, grossPct, profit, cm3, health, bucket };
});

