"use client";

import { useMemo, useState } from "react";
import { DeptHeader } from "@/components/shared/DeptHeader";
import { AIStrip } from "@/components/shared/AIStrip";
import { PeriodTabs } from "@/components/shared/PeriodTabs";
import { SectionLabel } from "@/components/shared/SectionLabel";
import { BridgePrimaryButton } from "@/features/bridge/components/BridgePrimaryButton";
import { MarginMapScatter } from "@/components/charts/MarginMapScatter";
import {
  PRODUCTS,
  HEALTH_COLOR,
  marginMetrics,
  marginAI,
  type MarginBucket,
  type MarginProduct,
} from "@/features/finance/api/finance-margins-data";
import "./margins.css";

const fmt = (v: number) =>
  `${v < 0 ? "−" : ""}$${Math.abs(Math.round(v)).toLocaleString()}`;
const fmtCM = (v: number) => `${v.toFixed(1)}%`;
const cmCls = (cm3: number) => (cm3 < 0 ? "red" : cm3 < 10 ? "amber" : "green");
const PERIOD_LABELS = ["This month", "Last 90 days", "Year to date"];

type SortKey = "name" | "rev" | "cogs" | "gross" | "ship" | "ads" | "ret" | "profit" | "cm3";
type Filter = "all" | "win" | "warn" | "loss";

export default function MarginsPage() {
  const [periodIdx, setPeriodIdx] = useState(0);
  const [selectedIdx, setSelectedIdx] = useState<number | null>(null);
  const [filter, setFilter] = useState<Filter>("all");
  const [search, setSearch] = useState("");
  const [sortKey, setSortKey] = useState<SortKey>("profit");
  const [sortDir, setSortDir] = useState<1 | -1>(-1);

  const rows = useMemo(() => {
    const q = search.toLowerCase();
    const filtered = PRODUCTS.filter((p) => {
      if (filter !== "all" && (p.bucket as MarginBucket) !== filter) return false;
      if (q && !p.name.toLowerCase().includes(q)) return false;
      return true;
    });
    return filtered.sort((a, b) => {
      let av: string | number;
      let bv: string | number;
      switch (sortKey) {
        case "name":
          av = a.name.toLowerCase();
          bv = b.name.toLowerCase();
          break;
        case "rev":
        case "cogs":
        case "ship":
        case "ads":
        case "ret":
        case "profit":
          av = a[sortKey];
          bv = b[sortKey];
          break;
        case "gross":
          av = a.gross;
          bv = b.gross;
          break;
        case "cm3":
          av = a.cm3;
          bv = b.cm3;
          break;
      }
      if (typeof av === "number" && typeof bv === "number") return (av - bv) * sortDir;
      return String(av).localeCompare(String(bv)) * sortDir;
    });
  }, [filter, search, sortKey, sortDir]);

  const sums = useMemo(
    () => ({
      rev: rows.reduce((a, p) => a + p.rev, 0),
      cost: rows.reduce((a, p) => a + p.cogs + p.ship + p.ads + p.ret, 0),
      profit: rows.reduce((a, p) => a + p.profit, 0),
    }),
    [rows],
  );

  const handleSort = (k: SortKey) => {
    if (sortKey === k) setSortDir((d) => (d === 1 ? -1 : 1));
    else {
      setSortKey(k);
      setSortDir(k === "name" ? 1 : -1);
    }
  };

  const totalProfit = PRODUCTS.reduce((a, p) => a + p.profit, 0);
  const winners = PRODUCTS.filter((p) => p.bucket === "win").length;
  const losers = PRODUCTS.filter((p) => p.bucket === "loss").length;

  const sellMore = [...PRODUCTS].sort((a, b) => b.profit - a.profit).slice(0, 4);
  const fixUp = [...PRODUCTS].sort((a, b) => a.cm3 - b.cm3).slice(0, 4);

  return (
    <div className="finance-margins-page">
      <DeptHeader
        dept="finance"
        title="Margin Analysis"
        meta={
          <>
            <span className="live">Live</span> · Which products actually make money — and which ones cost you · true profit per product
          </>
        }
        actions={
          <>
            <button className="btn-util">Export</button>
            <BridgePrimaryButton dept="finance">Fix in Bridge →</BridgePrimaryButton>
          </>
        }
      />

      <PeriodTabs labels={PERIOD_LABELS} activeIndex={periodIdx} onChange={setPeriodIdx} />

      {/* Metric strip */}
      <div className="metric-strip">
        <div className="metric">
          <div className="metric-l">Gross margin · CM1</div>
          <div className="metric-v">
            {marginMetrics.cm1}<span className="u">%</span>
          </div>
          <div className="metric-s">after COGS</div>
        </div>
        <div className="metric">
          <div className="metric-l">After shipping · CM2</div>
          <div className="metric-v">
            {marginMetrics.cm2}<span className="u">%</span>
          </div>
          <div className="metric-s">after fulfilment</div>
        </div>
        <div className="metric">
          <div className="metric-l">Contribution · CM3</div>
          <div className="metric-v green">
            {marginMetrics.cm3}<span className="u">%</span>
          </div>
          <div className="metric-s up">after ad spend</div>
        </div>
        <div className="metric">
          <div className="metric-l">Returns impact</div>
          <div className="metric-v red">{marginMetrics.returnsImpact}</div>
          <div className="metric-s down">{marginMetrics.returnsPct}</div>
        </div>
        <div className="metric">
          <div className="metric-l">Best product</div>
          <div className="metric-v" style={{ fontSize: 19 }}>
            {marginMetrics.bestProduct}
          </div>
          <div className="metric-s up">{marginMetrics.bestProductSub}</div>
        </div>
      </div>

      <AIStrip label={marginAI.label} meta={marginAI.meta} cards={marginAI.cards} />

      {/* Margin map */}
      <SectionLabel>The margin map — where every product really sits</SectionLabel>
      <div className="map-card">
        <div className="map-head">
          <div className="map-readout">
            <div className="rl">True profit this month · across {PRODUCTS.length} products</div>
            <div className="rv">{fmt(totalProfit)}</div>
            <div className="rsub">
              <b>{winners} products</b> earn it ·{" "}
              <b style={{ color: "var(--loss)" }}>{losers}</b> drain it
            </div>
          </div>
          <div className="map-legend">
            <div className="mleg">
              <span className="sw" style={{ background: "var(--d-finance)" }} />
              Profitable after all costs
            </div>
            <div className="mleg">
              <span className="sw" style={{ background: "var(--loss)" }} />
              Loses money after ads
            </div>
            <div className="mleg">
              <span className="ring" />
              Bubble size = revenue volume
            </div>
          </div>
        </div>

        <MarginMapScatter
          data={PRODUCTS}
          selectedIndex={selectedIdx}
          onSelect={setSelectedIdx}
        />
      </div>

      <div className="argument">
        <span className="mk" />
        <p>
          Gross margin is a flattering number. <b>Cylinder Stand sells well and shows 47% gross — but after ads it loses money on every order.</b> The products that earn you a living sit top-right; the ones quietly costing you sit bottom-left.
        </p>
      </div>

      {/* Panels */}
      <SectionLabel>What to do about it</SectionLabel>
      <div className="panels">
        <div className="panel">
          <div className="panel-head">
            <span className="pdot good" />
            <span>Sell more — highest true profit</span>
          </div>
          {sellMore.map((p) => {
            const idx = PRODUCTS.indexOf(p);
            return (
              <div
                key={p.name}
                className={`prow${selectedIdx === idx ? " sel" : ""}`}
                onClick={() => setSelectedIdx((c) => (c === idx ? null : idx))}
              >
                <div className="pname">
                  {p.name}
                  <span className="ps">{p.sub}</span>
                </div>
                <div className={`pcm3 ${cmCls(p.cm3)}`}>{fmtCM(p.cm3)}</div>
                <div className="pprof">{fmt(p.profit)}</div>
              </div>
            );
          })}
        </div>
        <div className="panel">
          <div className="panel-head">
            <span className="pdot bad" />
            <span>Fix or reconsider — margin problems</span>
          </div>
          {fixUp.map((p) => {
            const idx = PRODUCTS.indexOf(p);
            return (
              <div
                key={p.name}
                className={`prow${selectedIdx === idx ? " sel" : ""}`}
                onClick={() => setSelectedIdx((c) => (c === idx ? null : idx))}
              >
                <div className="pname">
                  {p.name}
                  <span className="ps">{p.sub}</span>
                </div>
                <div className={`pcm3 ${cmCls(p.cm3)}`}>{fmtCM(p.cm3)}</div>
                <div className="pprof">{fmt(p.profit)}</div>
              </div>
            );
          })}
        </div>
      </div>

      {/* Tools */}
      <div className="ldg-tools">
        <div className="pt-search">
          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8">
            <circle cx="11" cy="11" r="7" />
            <path d="M21 21l-4.3-4.3" />
          </svg>
          <input
            type="text"
            placeholder="Search products…"
            value={search}
            onChange={(e) => setSearch(e.target.value)}
          />
          <span className="search-count">{rows.length} products</span>
        </div>
        <div className="filters">
          {(["all", "win", "warn", "loss"] as Filter[]).map((f) => (
            <button
              key={f}
              className={`fchip${filter === f ? " active" : ""}`}
              onClick={() => setFilter(f)}
            >
              {f === "all" ? "All" : f === "win" ? "Profitable" : f === "warn" ? "At risk" : "Losing money"}
            </button>
          ))}
        </div>
      </div>

      {/* Product table */}
      <div className="ptable">
        <div className="pt-head">
          {(
            [
              { k: "name", l: "Product" },
              { k: "rev", l: "Revenue", num: true },
              { k: "cogs", l: "COGS", num: true },
              { k: "gross", l: "Gross", num: true },
              { k: "ship", l: "Shipping", num: true },
              { k: "ads", l: "Ads", num: true },
              { k: "ret", l: "Returns", num: true },
              { k: "profit", l: "True profit", num: true },
              { k: "cm3", l: "CM3 · health", num: true },
            ] as Array<{ k: SortKey; l: string; num?: boolean }>
          ).map((col) => {
            const active = sortKey === col.k;
            return (
              <span
                key={col.k}
                className={`th${col.num ? " num" : ""}${active ? " active" : ""}`}
                onClick={() => handleSort(col.k)}
              >
                {col.l} <i className="ar">{sortDir > 0 ? "↑" : "↓"}</i>
              </span>
            );
          })}
        </div>
        {rows.map((p: MarginProduct) => {
          const idx = PRODUCTS.indexOf(p);
          const profitCls = p.cm3 < 0 ? "red" : p.cm3 < 10 ? "amber" : "green";
          return (
            <div
              key={p.name}
              className={`pt-row${selectedIdx === idx ? " sel" : ""}`}
              onClick={() => setSelectedIdx((c) => (c === idx ? null : idx))}
            >
              <div className="pname">
                {p.name}
                <span className="ps">{p.sub}</span>
              </div>
              <div className="num">{fmt(p.rev)}</div>
              <div className="num">{fmt(p.cogs)}</div>
              <div className="num">{fmt(p.gross)}</div>
              <div className="num">{fmt(p.ship)}</div>
              <div className="num">{fmt(p.ads)}</div>
              <div className="num">{fmt(p.ret)}</div>
              <div className={`num profit ${profitCls}`}>{fmt(p.profit)}</div>
              <span className={`health-pill ${p.health}`}>
                <span className="d" />
                {fmtCM(p.cm3)}
              </span>
            </div>
          );
        })}
        <div className="ptable-foot">
          <span className="foot-note">{rows.length} products</span>
          <div className="foot-sums">
            <div className="foot-sum">
              <span className="l">Revenue</span>
              <span className="v">{fmt(sums.rev)}</span>
            </div>
            <div className="foot-sum">
              <span className="l">All costs</span>
              <span className="v red">{fmt(sums.cost)}</span>
            </div>
            <div className="foot-sum">
              <span className="l">True profit</span>
              <span className="v green">{fmt(sums.profit)}</span>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
